    if (g_handoverPredictor && g_ueNodes.GetN() > 0) {
        uint64_t imsi = 1;

        // 获取UE当前位置和速度
        Ptr<Node> ueNode = g_ueNodes.Get(0);
        Ptr<MobilityModel> mobilityModel = ueNode->GetObject<MobilityModel>();

        if (mobilityModel) {
            Vector position = mobilityModel->GetPosition();
