            measurementData.cellId = 1;  // 假设当前服务小区ID为1

            // 模拟RSRP随距离衰减
            double distance = std::sqrt(position.x * position.x + position.y * position.y);
            measurementData.rsrp = -70.0 - 20 * std::log10(distance / 100.0);  // 简单的路径损耗模型
