NS_LOG_COMPONENT_DEFINE("LteGridWithPredictor");

// 全局变量
std::string cwnd_tr_file_name = "cwndTr.txt";
std::string ssthresh_tr_file_name = "sshThTr.txt";
std::string rtt_tr_file_name = "rttTr.txt";
