{
    NS_LOG_FUNCTION(this << imsi);

    switch (m_algorithm)
    {
    case RSRP_TREND_BASED:
        return PredictByRsrpTrend(imsi);
    case VELOCITY_AWARE:
        return PredictByVelocity(imsi);
    case MACHINE_LEARNING:
