// 全局变量存储原始RSRP值
std::map<uint16_t, double> g_storedRsrpValues;

// 新的回调函数，用于接收原始RSRP值
void NotifyRawMeasurement(uint16_t cellId, double rsrp, double rsrq) {
    g_storedRsrpValues[cellId] = rsrp;
    std::cout << "原始测量值更新: 小区ID=" << cellId << " RSRP=" << std::fixed << std::setprecision(3) << rsrp << " dBm" << std::endl;
}

// 智能切换预测的测量报告处理函数
void NotifyUeMeasurement(std::string context, uint64_t imsi, uint16_t cellId, uint16_t rnti, LteRrcSap::MeasurementReport report) {
    // 尝试从全局存储中获取原始RSRP值
    double rsrpResults = 0.0;
    double rsrqResults = 0.0;

    // 首先尝试从全局存储获取原始值
    auto it = g_storedRsrpValues.find(cellId);
    if (it != g_storedRsrpValues.end()) {
        rsrpResults = it->second;
        std::cout << "使用原始RSRP值: " << std::fixed << std::setprecision(3) << rsrpResults << " dBm" << std::endl;
    } else {
        // 如果没有找到，使用转换后的值
        rsrpResults = (double)EutranMeasurementMapping::RsrpRange2Dbm(report.measResults.measResultPCell.rsrpResult);
        rsrqResults = (double)EutranMeasurementMapping::RsrqRange2Db(report.measResults.measResultPCell.rsrqResult);
        std::cout << "使用转换后的RSRP值: " << std::fixed << std::setprecision(3) << rsrpResults << " dBm" << std::endl;
    }

    std::cout << "==========测量报告========== " << Simulator::Now().GetSeconds() << "s "
              << " UE IMSI=" << imsi << " 服务小区ID=" << cellId
              << " 服务小区RSRP: " << std::fixed << std::setprecision(3) << rsrpResults << " dBm" << std::endl;

