    Simulator::Run();

    // 仿真结束后的处理
    for (uint32_t appIdx = 0; appIdx < sinkApps.GetN(); appIdx++) {
        Ptr<PacketSink> sink1 = DynamicCast<PacketSink>(sinkApps.Get(appIdx));
