    }

    anim.UpdateNodeColor(remoteHost, 0, 0, 255);  // 远程主机为蓝色
    anim.UpdateNodeSize(0, 15, 15);

    for (uint32_t i = 0; i < g_enbNodes.GetN(); ++i) {
        anim.UpdateNodeColor(g_enbNodes.Get(i), 0, 255, 0);  // 基站为绿色
        anim.UpdateNodeSize(i, 15, 15);
